514	+/// Greedy fill layout (BEHAVIOR.md §3f). Starting from `open_text` at column
515	+/// `start_col`, place each unit's separator on the current line and then its text,
516	+/// wrapping to the unit's indent when the text would pass [`FILL_WIDTH`] (or on a
517	+/// `hard` unit). Returns the physical lines.
518	+fn run_layout(open_text: &str, start_col: usize, units: &[Unit]) -> Vec<PLine> {
519	+    let mut lines: Vec<PLine> = Vec::new();
520	+    let mut cur = open_text.to_string();
521	+    let mut col = start_col;
522	+    let mut line_indent = 0usize;
523	+    for u in units {
524	+        cur.push_str(u.sep);
525	+        col += width(u.sep);
526	+        let w = width(&u.text);
527	+        if u.hard || col + w > FILL_WIDTH {
528	+            lines.push((line_indent, std::mem::take(&mut cur)));
529	+            line_indent = u.indent;
530	+            cur.push_str(&u.text);
531	+            col = u.indent + w;
532	+        } else {
533	+            cur.push_str(&u.text);
534	+            col += w;
535	+        }
536	+    }
537	+    lines.push((line_indent, cur));
538	+    lines
