541	+/// Split `s` at top-level occurrences of `", "` — respecting `()`/`<>`/`[]` nesting
542	+/// and `'…'` quotes — into the comma-separated elements of a fill group.
543	+fn split_top_commas(s: &str) -> Vec<String> {
544	+    let chars: Vec<char> = s.chars().collect();
545	+    let mut parts: Vec<String> = Vec::new();
546	+    let mut cur = String::new();
547	+    let mut depth = 0i32;
548	+    let mut in_quote = false;
549	+    let mut i = 0;
550	+    while i < chars.len() {
551	+        let c = chars[i];
552	+        if in_quote {
553	+            cur.push(c);
554	+            if c == '\'' {
555	+                in_quote = false;
556	+            }
557	+            i += 1;
558	+            continue;
559	+        }
560	+        match c {
561	+            '\'' => {
562	+                in_quote = true;
563	+                cur.push(c);
564	+                i += 1;
565	+            }
566	+            '(' | '<' | '[' => {
567	+                depth += 1;
568	+                cur.push(c);
569	+                i += 1;
570	+            }
571	+            ')' | '>' | ']' => {
572	+                depth -= 1;
573	+                cur.push(c);
574	+                i += 1;
575	+            }
576	+            ',' if depth == 0 && i + 1 < chars.len() && chars[i + 1] == ' ' => {
577	+                parts.push(std::mem::take(&mut cur));
578	+                i += 2;
579	+            }
580	+            _ => {
581	+                cur.push(c);
582	+                i += 1;
583	+            }
584	+        }
585	+    }
586	+    parts.push(cur);
587	+    parts
588	+}
