610	+/// argument column; a sole tuple argument recurses into [`layout_tuple`]; and the
611	+/// closing `)` peels onto its own line at column 0 (the padded ` )` space becomes
612	+/// the break).
613	+fn layout_fact(flat: &str) -> Vec<PLine> {
614	+    if width(flat) <= FILL_WIDTH {
615	+        return vec![(0, flat.to_string())];
616	+    }
617	+    let Some(lp) = flat.find("( ") else {
618	+        return vec![(0, flat.to_string())];
619	+    };
620	+    if !flat.ends_with(" )") {
621	+        return vec![(0, flat.to_string())];
622	+    }
623	+    let open_str = &flat[..lp + 2]; // "NAME( "
624	+    let content = &flat[lp + 2..flat.len() - 2];
625	+    let open_col = width(open_str);
626	+    let args = split_top_commas(content);
627	+
628	+    // A sole tuple argument: the fact opens "NAME( <" and the tuple fills inside.
629	+    if args.len() == 1 && is_tuple(&args[0]) {
630	+        let inner = &args[0][1..args[0].len() - 1];
631	+        let tlines = layout_tuple(inner, open_col);
632	+        let mut lines: Vec<PLine> = Vec::with_capacity(tlines.len() + 2);
633	+        lines.push((0, format!("{}{}", open_str, tlines[0].1)));
634	+        for t in &tlines[1..] {
635	+            lines.push(t.clone());
636	+        }
637	+        lines.push((0, ")".to_string()));
638	+        return lines;
639	+    }
