652	+/// trailing `,` kept on each non-final line and the `]` attached to the last
653	+/// action.
654	+fn layout_info(flat: &str) -> Vec<PLine> {
655	+    if width(flat) <= FILL_WIDTH {
656	+        return vec![(0, flat.to_string())];
657	+    }
658	+    let Some(lb) = flat.find('[') else {
659	+        return vec![(0, flat.to_string())];
660	+    };
661	+    if !flat.ends_with(']') {
662	+        return vec![(0, flat.to_string())];
663	+    }
664	+    let open_str = &flat[..lb + 1]; // "#t : Rule["
665	+    let content = &flat[lb + 1..flat.len() - 1];
666	+    let open_col = width(open_str);
667	+    let acts = split_top_commas(content);
668	+    let mut units: Vec<Unit> = Vec::with_capacity(acts.len());
669	+    for (i, a) in acts.iter().enumerate() {
670	+        // Each action begins its own line (a vertical `sep`, hard break after the
671	+        // first); non-final actions carry a trailing `,`, the last carries `]`.
672	+        let text = if i + 1 < acts.len() { format!("{},", a) } else { format!("{}]", a) };
673	+        units.push(Unit { sep: "", text, indent: open_col, hard: i > 0 });
674	+    }
