685	+/// with the delimiter peel. The same entry serves the Term-based path (feed
686	+/// [`Fact::render_flat`]) and the pre-rendered-string path (feed the caller's
687	+/// already-rendered cell text): the wrap and escape apply identically.
688	+pub fn wrap_cell(flat: &str) -> String {
689	+    let lines = if flat.starts_with('#') && flat.contains('[') {
690	+        layout_info(flat)
691	+    } else {
692	+        layout_fact(flat)
